const rows = $('Traer conversaciones del dia').all().map(i => i.json);
const adSessions = new Set($input.all().map(i => i.json.session_id));

const bySession = {};
for (const r of rows) {
  if (!bySession[r.session_id]) bySession[r.session_id] = [];
  bySession[r.session_id].push({ role: r.role, content: r.content });
}

const PRECIO = 43000;
const COSTO = 10000;
const GANANCIA_UNIT = PRECIO - COSTO;

let totalConversaciones = 0;
let ventasCerradas = 0;

for (const [sessionId, msgs] of Object.entries(bySession)) {
  if (!adSessions.has(sessionId)) continue; // solo conversaciones iniciadas por un anuncio hoy
  totalConversaciones++;
  const gotPaymentInfo = msgs.some(m => m.role === 'assistant' && m.content.includes('Alias: productoscapilarespg'));
  const sentReceipt = msgs.some(m => m.role === 'user' && m.content.includes('Imagen recibida'));
  if (gotPaymentInfo && sentReceipt) ventasCerradas++;
}

const conversionPct = totalConversaciones > 0 ? ((ventasCerradas / totalConversaciones) * 100).toFixed(1) : '0.0';
const facturacion = ventasCerradas * PRECIO;
const ganancia = ventasCerradas * GANANCIA_UNIT;
const fmt = n => n.toLocaleString('es-AR');

const hoy = new Date().toLocaleDateString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires', day: '2-digit', month: '2-digit', year: 'numeric' });

let text = `\u{1F4C5} Resumen del dia (${hoy})\n\n`;
text += `\u{1F4AC} Conversaciones desde anuncios: ${totalConversaciones}\n`;
text += `\u{1F6D2} Ventas cerradas: ${ventasCerradas}\n`;
text += `\u{1F4C8} Conversion: ${conversionPct}%\n`;
if (ventasCerradas > 0) {
  text += `\u{1F4B0} Facturacion: $${fmt(facturacion)}\n`;
  text += `\u{2705} Ganancia neta: $${fmt(ganancia)}`;
} else {
  text += `\u{1F4B0} Sin ventas cerradas hoy.`;
}

return [{ json: { text } }];
